package il.co.dcd.composermapper.model; import java.nio.file.Path; import java.util.*;
public class OperationDef { private String id; private String operationContext; private Path sourceFile; private final Map<String,String> rawAttributes=new LinkedHashMap<>(); private final List<OpStepDef> steps=new ArrayList<>(); private final Map<String,String> refFormats=new LinkedHashMap<>(); private final List<String> inlineFormatIds=new ArrayList<>(); public String getId(){return id;} public void setId(String id){this.id=id;} public String getOperationContext(){return operationContext;} public void setOperationContext(String v){this.operationContext=v;} public Path getSourceFile(){return sourceFile;} public void setSourceFile(Path p){this.sourceFile=p;} public Map<String,String> getRawAttributes(){return rawAttributes;} public List<OpStepDef> getSteps(){return steps;} public Map<String,String> getRefFormats(){return refFormats;} public List<String> getInlineFormatIds(){return inlineFormatIds;} }
